targets.expr:
((
  sum(
    (
      (max by (instance_type, zone) (
  karpenter_cloudprovider_instance_type_offering_price_estimate{
    cluster="$cluster",
job=~"$job"
,
    zone=~"$zone",
    instance_type=~"$instance_type",
    capacity_type="on-demand"
  }
)
) - (max by (instance_type, zone) (
  karpenter_cloudprovider_instance_type_offering_price_estimate{
    cluster="$cluster",
job=~"$job"
,
    zone=~"$zone",
    instance_type=~"$instance_type",
    capacity_type="spot"
  }
)
)
    )
    * on (instance_type, zone)
    (
      count by (region, zone, instance_type) (
  max by (node_name, region, zone, instance_type) (
    karpenter_nodes_allocatable{
      cluster="$cluster",
job=~"$job"
,
nodepool=~"$nodepool"
,
region=~"$region",
zone=~"$zone"
,
      arch=~"$arch",
      os=~"$os",
      instance_type=~"$instance_type",
      resource_type="cpu"
    }
  )
)

    )
  )
) or on() vector(0)
) * 730

avg by (instance_type, capacity_type) (
  max by (instance_type, capacity_type, zone) (
  karpenter_cloudprovider_instance_type_offering_price_estimate{
    cluster="$cluster",
job=~"$job"
,
    zone=~"$zone",
    instance_type=~"$instance_type",
    capacity_type=~"$capacity_type"
  }
)

) * 730

((
  0 * sum by (nodepool) (
